import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function VideoPlayerPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [video, setVideo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isAuthor, setIsAuthor] = useState(false);
  const [deleting, setDeleting] = useState(false);

  // Получаем текущего пользователя из токена
  const getCurrentUser = () => {
    const token = localStorage.getItem('access');
    if (!token) return null;
    
    try {
      const payload = JSON.parse(atob(token.split('.')[1]));
      return payload.username;
    } catch (e) {
      return null;
    }
  };

  useEffect(() => {
    const fetchVideo = async () => {
      try {
        const response = await axios.get(`http://localhost:8000/api/videos/${id}/`);
        setVideo(response.data);
        
        const currentUser = getCurrentUser();
        if (currentUser && response.data.uploaded_by_name === currentUser) {
          setIsAuthor(true);
        }
        
        setLoading(false);
      } catch (error) {
        console.error('Ошибка:', error);
        setError('Видео не найдено');
        setLoading(false);
      }
    };
    
    fetchVideo();
  }, [id]);

  const handleDelete = async () => {
    if (!window.confirm('Вы уверены, что хотите удалить это видео?')) {
      return;
    }
    
    const token = localStorage.getItem('access');
    if (!token) {
      alert('Сначала войдите в систему');
      navigate('/login');
      return;
    }
    
    setDeleting(true);
    try {
      await axios.delete(`http://localhost:8000/api/videos/${id}/`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      alert('Видео успешно удалено');
      navigate('/');
    } catch (error) {
      console.error('Ошибка удаления:', error);
      alert('Не удалось удалить видео. Возможно, у вас нет прав.');
    } finally {
      setDeleting(false);
    }
  };

  if (loading) {
    return <div style={{ color: 'white', textAlign: 'center', marginTop: 50 }}>Загрузка...</div>;
  }

  if (error || !video) {
    return <div style={{ color: 'white', textAlign: 'center', marginTop: 50 }}>{error || 'Видео не найдено'}</div>;
  }

  const videoUrl = `http://localhost:8000/api/videos/${id}/stream/`;

  return (
    <div style={{ maxWidth: 1200, margin: '0 auto' }}>
      <video
        src={videoUrl}
        controls
        autoPlay
        style={{ 
          width: '100%', 
          borderRadius: 12, 
          backgroundColor: '#000',
          maxHeight: '80vh',      // ← НЕ ДАЁТ ВЫЙТИ ЗА РАМКИ
          objectFit: 'contain'     // ← ВПИСЫВАЕТ ВЕРТИКАЛЬНОЕ ВИДЕО
        }}
      >
        <source src={videoUrl} type="video/mp4" />
        Ваш браузер не поддерживает видео тег.
      </video>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 20 }}>
        <h1 style={{ color: 'white', margin: 0 }}>{video.title}</h1>
        
        {isAuthor && (
          <button 
            onClick={handleDelete}
            disabled={deleting}
            style={{
              backgroundColor: '#ff0000',
              color: 'white',
              border: 'none',
              padding: '10px 20px',
              borderRadius: 8,
              cursor: deleting ? 'not-allowed' : 'pointer',
              fontSize: 14,
              display: 'flex',
              alignItems: 'center',
              gap: 8
            }}
          >
            🗑️ {deleting ? 'Удаление...' : 'Удалить видео'}
          </button>
        )}
      </div>
      
      <p style={{ color: '#aaa', marginTop: 10 }}>{video.description}</p>
      
      <div style={{ color: '#888', marginTop: 10 }}>
        👤 {video.uploaded_by_name || 'Аноним'} • 👁️ {video.views || 0} просмотров
      </div>
    </div>
  );
}

export default VideoPlayerPage;
